import{_ as s,o as e,c as t,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Resilience and redundancy","description":"Your file survives us. Both of us.","frontmatter":{"description":"Your file survives us. Both of us."},"headers":[],"relativePath":"concepts/resilience.md","filePath":"concepts/resilience.md","lastUpdated":1777130260000}'),n={name:"concepts/resilience.md"};function r(l,a,o,d,p,h){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="resilience-and-redundancy" tabindex="-1">Resilience and redundancy <a class="header-anchor" href="#resilience-and-redundancy" aria-label="Permalink to &quot;Resilience and redundancy&quot;">​</a></h1><p>A single prover can fail. They might run out of disk, lose power, get DDoS&#39;d, refuse to serve, or just decide to leave the network. Prova&#39;s resilience model handles all of these.</p><h2 id="how-redundancy-works" tabindex="-1">How redundancy works <a class="header-anchor" href="#how-redundancy-works" aria-label="Permalink to &quot;How redundancy works&quot;">​</a></h2><p>When you upload a file, you choose a <strong>redundancy factor</strong> (default: 4). The piece is pinned to that many independent provers. They each have their own deal and their own stake.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              ┌──── Prover A (Reykjavík) ──── alive</span></span>
<span class="line"><span>              ├──── Prover B (Singapore) ──── alive</span></span>
<span class="line"><span>   piece-cid ─┤</span></span>
<span class="line"><span>              ├──── Prover C (São Paulo) ──── alive</span></span>
<span class="line"><span>              └──── Prover D (Frankfurt) ──── alive</span></span></code></pre></div><p>If Prover A goes down, retrieval falls through to B/C/D automatically. Prover A&#39;s stake gets slashed. The marketplace re-lists the slot, and a healthy prover picks it up — bringing redundancy back to 4.</p><p>You can simulate this in the <a href="https://prova.network/#redundancy" target="_blank" rel="noreferrer">redundancy lab</a> on the homepage.</p><h2 id="choosing-a-redundancy-factor" tabindex="-1">Choosing a redundancy factor <a class="header-anchor" href="#choosing-a-redundancy-factor" aria-label="Permalink to &quot;Choosing a redundancy factor&quot;">​</a></h2><p>Higher redundancy = higher cost, higher durability. Some rules of thumb:</p><table tabindex="0"><thead><tr><th>Use case</th><th>Suggested redundancy</th></tr></thead><tbody><tr><td>Personal backup</td><td>2</td></tr><tr><td>Static website (ENS contenthash)</td><td>3</td></tr><tr><td>Research dataset</td><td>4 (default)</td></tr><tr><td>AI training corpus</td><td>5</td></tr><tr><td>Critical archival (cultural memory, legal records)</td><td>6+</td></tr></tbody></table><p>Each replica is a separate deal, so the cost scales linearly. Storing a 1 GB file at redundancy 4 costs ~4× the per-replica price.</p><h2 id="geographic-distribution" tabindex="-1">Geographic distribution <a class="header-anchor" href="#geographic-distribution" aria-label="Permalink to &quot;Geographic distribution&quot;">​</a></h2><p>By default, Prova spreads replicas across <strong>regions</strong> (continents). You can override:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> prova.storage.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">upload</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(bytes, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  redundancy: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  regions: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EU&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;NA&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;AP&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SA&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// explicit regions</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>Or constrain to a single region (for latency):</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> prova.storage.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">upload</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(bytes, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  redundancy: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  regions: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EU&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><h2 id="what-happens-during-a-failure" tabindex="-1">What happens during a failure <a class="header-anchor" href="#what-happens-during-a-failure" aria-label="Permalink to &quot;What happens during a failure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t=0    Prover A fails. Stops posting proofs.</span></span>
<span class="line"><span>t=30s  First missed proof on-chain.</span></span>
<span class="line"><span>t=60s  Second missed proof. Marketplace flags the deal.</span></span>
<span class="line"><span>t=90s  Third missed proof. Deal terminated.</span></span>
<span class="line"><span>       Prover A&#39;s stake is slashed by 5% (configurable).</span></span>
<span class="line"><span>       Refund of remaining escrow is queued.</span></span>
<span class="line"><span>t=120s Marketplace re-lists the slot.</span></span>
<span class="line"><span>       The piece is broadcast as &quot;needs replication&quot;.</span></span>
<span class="line"><span>t=180s Healthy prover picks it up, copies from a sibling replica.</span></span>
<span class="line"><span>       Redundancy is restored to 4.</span></span></code></pre></div><p>Total downtime for the affected replica: ~3 minutes. Total downtime for the <strong>piece itself</strong> (retrieval availability): zero, because the other replicas are still serving.</p><h2 id="slashing-parameters" tabindex="-1">Slashing parameters <a class="header-anchor" href="#slashing-parameters" aria-label="Permalink to &quot;Slashing parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>Slash</th></tr></thead><tbody><tr><td>Single missed proof</td><td>0% (warning)</td></tr><tr><td>3 consecutive missed proofs</td><td>5% of stake</td></tr><tr><td>Sustained failure (10+ misses)</td><td>25%</td></tr><tr><td>Deletion (proof of non-possession)</td><td>100% + ban</td></tr></tbody></table><p>These are configurable per-deal in <code>StorageMarketplace.sol</code> but defaults are conservative.</p><h2 id="probabilistic-durability" tabindex="-1">Probabilistic durability <a class="header-anchor" href="#probabilistic-durability" aria-label="Permalink to &quot;Probabilistic durability&quot;">​</a></h2><p>If each prover has 99% uptime independently, your <strong>piece</strong> durability with <code>r</code> replicas is <code>1 - (0.01)^r</code>:</p><table tabindex="0"><thead><tr><th>r</th><th>Piece durability</th></tr></thead><tbody><tr><td>1</td><td>99%</td></tr><tr><td>2</td><td>99.99%</td></tr><tr><td>3</td><td>99.9999%</td></tr><tr><td>4</td><td>99.999999%</td></tr><tr><td>5</td><td>99.99999999%</td></tr></tbody></table><p>That&#39;s <strong>eight nines</strong> at the default redundancy of 4. Compare to S3&#39;s 11 nines (single-region) — Prova catches up by <code>r = 6</code>, with the additional benefit of being multi-jurisdictional.</p><h2 id="when-redundancy-isn-t-enough" tabindex="-1">When redundancy isn&#39;t enough <a class="header-anchor" href="#when-redundancy-isn-t-enough" aria-label="Permalink to &quot;When redundancy isn&#39;t enough&quot;">​</a></h2><p>For data that <strong>must not be lost</strong> (cultural archives, legal records, medical research), you can:</p><ol><li>Set redundancy to 6+</li><li>Constrain to specific operators you trust</li><li>Combine Prova with an air-gapped local backup (cold tape, S3 Glacier)</li><li>Index the on-chain proofs yourself, so you can detect a network-wide failure even if the API is down</li></ol><p>Prova is the <strong>active</strong> layer of a defense-in-depth strategy. It&#39;s better than S3, but it&#39;s not a replacement for owning your own copy of the bytes that matter most.</p>`,30)])])}const g=s(n,[["render",r]]);export{u as __pageData,g as default};
